using Asp.Versioning;using Fixar.Application.Common.Models;using Fixar.Infrastructure.Identity;using Fixar.Infrastructure.Persistence;using Microsoft.AspNetCore.Authorization;using Microsoft.AspNetCore.Mvc;using Microsoft.EntityFrameworkCore;namespace Fixar.API.Controllers;[ApiController,ApiVersion("1.0"),Route("api/v{version:apiVersion}/supplier-ledger"),Authorize(Policy=AuthorizationPolicies.CanViewSupplierLedger)]public class SupplierLedgerController(ApplicationDbContext db):ControllerBase{[HttpGet("supplier/{id:guid}")]public async Task<IActionResult>Entries(Guid id,CancellationToken ct)=>Ok(ApiResponse<object>.SuccessResponse(await db.SupplierLedgerEntries.AsNoTracking().Where(x=>x.SupplierId==id).OrderBy(x=>x.TransactionDate).Select(x=>new{x.Id,x.EntryNumber,x.TransactionDate,x.DueDate,x.EntryType,x.SourceType,x.ReferenceNumber,x.Currency,x.DebitAmount,x.CreditAmount,x.Description}).ToListAsync(ct)));[HttpGet("supplier/{id:guid}/balance")]public async Task<IActionResult>Balance(Guid id,CancellationToken ct)=>Ok(ApiResponse<object>.SuccessResponse(await db.SupplierLedgerEntries.AsNoTracking().Where(x=>x.SupplierId==id).GroupBy(x=>x.Currency).Select(g=>new{Currency=g.Key,Credit=g.Sum(x=>x.CreditAmount),Debit=g.Sum(x=>x.DebitAmount),Balance=g.Sum(x=>x.CreditAmount-x.DebitAmount)}).ToListAsync(ct)));[HttpGet("supplier/{id:guid}/statement")]public async Task<IActionResult>Statement(Guid id,CancellationToken ct){var es=await db.SupplierLedgerEntries.AsNoTracking().Where(x=>x.SupplierId==id).OrderBy(x=>x.TransactionDate).ThenBy(x=>x.Created).ToListAsync(ct);var balances=new Dictionary<string,decimal>();var rows=es.Select(x=>{balances[x.Currency]=balances.GetValueOrDefault(x.Currency)+x.CreditAmount-x.DebitAmount;return new{x.Id,x.TransactionDate,x.ReferenceNumber,x.SourceType,x.DueDate,x.DebitAmount,x.CreditAmount,RunningBalance=balances[x.Currency],x.Currency,x.Description};});return Ok(ApiResponse<object>.SuccessResponse(rows));}[HttpGet("aging")]public async Task<IActionResult>Aging(CancellationToken ct){var today=DateTime.UtcNow.Date;var raw=await db.SupplierPayables.AsNoTracking().Where(x=>!x.IsCancelled&&x.OutstandingAmount>0).Select(x=>new{x.SupplierId,Supplier=x.Supplier.Name,x.Currency,x.DueDate,x.OutstandingAmount}).ToListAsync(ct);var rows=raw.GroupBy(x=>new{x.SupplierId,x.Supplier,x.Currency}).Select(g=>new{g.Key.SupplierId,g.Key.Supplier,g.Key.Currency,NotDue=g.Where(x=>x.DueDate>=today).Sum(x=>x.OutstandingAmount),Days1To30=g.Where(x=>(today-x.DueDate.Date).Days is>=1 and<=30).Sum(x=>x.OutstandingAmount),Days31To60=g.Where(x=>(today-x.DueDate.Date).Days is>=31 and<=60).Sum(x=>x.OutstandingAmount),Days61To90=g.Where(x=>(today-x.DueDate.Date).Days is>=61 and<=90).Sum(x=>x.OutstandingAmount),Days91To180=g.Where(x=>(today-x.DueDate.Date).Days is>=91 and<=180).Sum(x=>x.OutstandingAmount),Days181Plus=g.Where(x=>(today-x.DueDate.Date).Days>=181).Sum(x=>x.OutstandingAmount),TotalOutstanding=g.Sum(x=>x.OutstandingAmount),Count=g.Count(),OldestDue=g.Min(x=>x.DueDate)});return Ok(ApiResponse<object>.SuccessResponse(rows));}[HttpGet("forecast"),Authorize(Policy=AuthorizationPolicies.CanViewPaymentForecast)]public async Task<IActionResult>Forecast(CancellationToken ct){var t=DateTime.UtcNow.Date;var rows=await db.SupplierPayables.AsNoTracking().Where(x=>!x.IsCancelled&&x.OutstandingAmount>0).OrderBy(x=>x.DueDate).Select(x=>new{x.Id,x.PayableNumber,Supplier=x.Supplier.Name,x.DueDate,x.OutstandingAmount,x.Currency,x.Status,Bucket=x.DueDate<t?"Overdue":x.DueDate==t?"Today":x.DueDate<=t.AddDays(7)?"Next7Days":x.DueDate<=t.AddDays(30)?"Next30Days":x.DueDate<=t.AddDays(60)?"Next60Days":"Later"}).ToListAsync(ct);return Ok(ApiResponse<object>.SuccessResponse(rows));}[HttpGet("summary")]public async Task<IActionResult>Summary(CancellationToken ct)=>Ok(ApiResponse<object>.SuccessResponse(await db.SupplierLedgerEntries.AsNoTracking().GroupBy(x=>x.Currency).Select(g=>new{Currency=g.Key,Credit=g.Sum(x=>x.CreditAmount),Debit=g.Sum(x=>x.DebitAmount),Balance=g.Sum(x=>x.CreditAmount-x.DebitAmount)}).ToListAsync(ct)));}
